import anthropic, hashlib, os, json
from datetime import datetime, timezone

def deploy_with_metadata(system_prompt: str, tool_schemas: list) -> dict:
    """Record deployment metadata including prompt hash for auditability."""
    prompt_hash = hashlib.sha256(system_prompt.encode()).hexdigest()[:16]
    schema_hash = hashlib.sha256(
        json.dumps(tool_schemas, sort_keys=True).encode()
    ).hexdigest()[:16]

    metadata = {
        "deployed_at": datetime.now(timezone.utc).isoformat(),
        "prompt_hash": prompt_hash,
        "schema_hash": schema_hash,
        "git_sha": os.environ.get("GITHUB_SHA", "local"),
        "branch": os.environ.get("GITHUB_REF_NAME", "unknown"),
    }

    # Log metadata to deployment record (e.g. S3, Datadog, internal registry)
    print(f"DEPLOY: prompt={prompt_hash}, schema={schema_hash}, git={metadata['git_sha']}")
    return metadata

def create_client_with_metadata(metadata: dict) -> anthropic.Anthropic:
    """Create Anthropic client and attach deployment metadata to request headers."""
    return anthropic.Anthropic(
        default_headers={
            "X-Deployment-ID": metadata["git_sha"],
            "X-Prompt-Hash": metadata["prompt_hash"],
        }
    )
